import { useState, useEffect, useRef } from 'react';
import { Mail, MapPin, Clock, Send, CheckCircle, AlertCircle, ArrowRight, Zap, MessageSquare } from 'lucide-react';

/* ══════════════════════════════════════════════════════════
   EMAILJS CONFIG
   1. Go to https://emailjs.com — create a free account
   2. Add a Gmail service → copy the Service ID
   3. Create a template with variables:
      {{from_name}}, {{from_email}}, {{phone}},
      {{subject}}, {{message}}, {{to_email}}
   4. Copy Template ID + Public Key below
══════════════════════════════════════════════════════════ */
const EJS_SERVICE  = 'service_ujmr6hv';
const EJS_TEMPLATE = 'YOUR_TEMPLATE_ID';
const EJS_KEY      = 'YOUR_PUBLIC_KEY';
const TO_EMAIL     = 'synnoviqtech.support@gmail.com';
const CONFIGURED   = EJS_SERVICE !== 'YOUR_SERVICE_ID';

const MAP_SRC = "https://www.google.com/maps/embed?pb=!1m18!1m12!1m3!1d3935.5!2d77.8616722!3d9.1810413!2m3!1f0!2f0!3f0!3m2!1i1024!2i768!4f13.1!3m3!1m2!1s0x3b06b38506c749d9%3A0x1e0362e248249a58!2sKovilpatti%2C%20Tamil%20Nadu%20628502!5e0!3m2!1sen!2sin!4v1700000000000!5m2!1sen!2sin";

function useInView(threshold) {
  const ref = useRef(null);
  const [vis, setVis] = useState(false);
  useEffect(() => {
    const io = new IntersectionObserver(([e]) => {
      if (e.isIntersecting) { setVis(true); io.disconnect(); }
    }, { threshold: threshold || 0.1 });
    if (ref.current) io.observe(ref.current);
    return () => io.disconnect();
  }, [threshold]);
  return [ref, vis];
}

function Grain() {
  return (
    <div style={{position:'fixed',inset:0,zIndex:9999,pointerEvents:'none',opacity:.022}}>
      <svg width="100%" height="100%">
        <filter id="gr"><feTurbulence type="fractalNoise" baseFrequency="0.65" numOctaves="3" stitchTiles="stitch"/><feColorMatrix type="saturate" values="0"/></filter>
        <rect width="100%" height="100%" filter="url(#gr)"/>
      </svg>
    </div>
  );
}

function ProgressBar() {
  const [p,setP] = useState(0);
  useEffect(() => {
    const fn = () => { const d = document.documentElement; setP(d.scrollTop/(d.scrollHeight-d.clientHeight)); };
    window.addEventListener('scroll', fn, {passive:true});
    return () => window.removeEventListener('scroll', fn);
  }, []);
  return (
    <div style={{position:'fixed',top:0,left:0,right:0,height:3,zIndex:9999}}>
      <div style={{height:'100%',background:'linear-gradient(90deg,#0057ff,#7c3aed,#db2777)',transformOrigin:'left',transform:`scaleX(${p})`,transition:'none',willChange:'transform'}}/>
    </div>
  );
}

function Hero() {
  const [mx, setMx] = useState(0.5);
  const [my, setMy] = useState(0.5);
  useEffect(() => {
    const fn = e => { setMx(e.clientX/window.innerWidth); setMy(e.clientY/window.innerHeight); };
    window.addEventListener('mousemove', fn);
    return () => window.removeEventListener('mousemove', fn);
  }, []);
  return (
    <section style={{position:'relative',minHeight:'100vh',display:'flex',alignItems:'center',overflow:'hidden',background:'linear-gradient(135deg,#020810 0%,#0d1b4b 40%,#0a0d1e 100%)'}}>
      <div style={{position:'absolute',top:'-10%',left:'-5%',width:'70vw',height:'70vw',borderRadius:'50%',background:'radial-gradient(circle,rgba(0,87,255,.35) 0%,transparent 65%)',transform:`translate(${mx*40}px,${my*30}px)`,transition:'transform 1.2s cubic-bezier(.16,1,.3,1)',pointerEvents:'none'}}/>
      <div style={{position:'absolute',bottom:'-15%',right:'-5%',width:'55vw',height:'55vw',borderRadius:'50%',background:'radial-gradient(circle,rgba(124,58,237,.3) 0%,transparent 65%)',transform:`translate(${-mx*30}px,${-my*25}px)`,transition:'transform 1.5s cubic-bezier(.16,1,.3,1)',pointerEvents:'none'}}/>
      <div style={{position:'absolute',inset:0,backgroundImage:'linear-gradient(rgba(255,255,255,.03) 1px,transparent 1px),linear-gradient(90deg,rgba(255,255,255,.03) 1px,transparent 1px)',backgroundSize:'72px 72px',pointerEvents:'none'}}/>
      {[0,1,2].map(i=>(
        <div key={i} style={{position:'absolute',top:0,right:`${20+i*8}%`,width:1,height:'100%',background:`linear-gradient(to bottom,transparent,rgba(0,87,255,${.15-i*.04}),transparent)`,transform:'skewX(-15deg)',pointerEvents:'none'}}/>
      ))}
      <div style={{position:'relative',zIndex:1,padding:'120px clamp(28px,7vw,100px) 80px',maxWidth:1200,width:'100%',margin:'0 auto'}}>
        <div style={{display:'flex',alignItems:'center',gap:10,marginBottom:32,animation:'slideUp .6s .05s both'}}>
          <div style={{width:8,height:8,borderRadius:'50%',background:'#4ade80',boxShadow:'0 0 16px #4ade80',animation:'gPulse 2s infinite'}}/>
          <span style={{fontSize:'.62rem',fontWeight:700,letterSpacing:'.26em',textTransform:'uppercase',color:'rgba(255,255,255,.5)'}}>Available Now</span>
          <div style={{width:40,height:1,background:'rgba(255,255,255,.15)'}}/>
          <span style={{fontSize:'.62rem',fontWeight:700,letterSpacing:'.1em',color:'rgba(0,87,255,.8)'}}>1 Business Day Response</span>
        </div>
        <div style={{marginBottom:40}}>
          {["Let's Build","Something","Together."].map((line,i)=>(
            <div key={i} style={{overflow:'hidden'}}>
              <h1 style={{fontFamily:'var(--serif)',fontSize:'clamp(3.5rem,9vw,9rem)',fontWeight:900,lineHeight:.9,letterSpacing:'-.055em',margin:0,animation:`slideUp .75s ${.08+i*.1}s both`,color:i===1?'transparent':i===2?'rgba(255,255,255,.15)':'#fff',background:i===1?'linear-gradient(90deg,#4d9fff,#a78bfa,#f472b6)':'none',WebkitBackgroundClip:i===1?'text':'unset',WebkitTextFillColor:i===1?'transparent':'unset',WebkitTextStroke:i===2?'1px rgba(255,255,255,.2)':'0'}}>{line}</h1>
            </div>
          ))}
        </div>
        <div style={{display:'grid',gridTemplateColumns:'1fr auto',gap:40,alignItems:'end',animation:'slideUp .7s .4s both'}} className="hero-bottom">
          <p style={{fontSize:'clamp(.9rem,1.4vw,1.05rem)',color:'rgba(255,255,255,.4)',lineHeight:1.9,maxWidth:440}}>
            Have a project in mind? We're a full stack &amp; game development studio — drop us a message and we'll get back within one business day.
          </p>
          <div style={{display:'flex',gap:32}}>
            {[['50+','Projects'],['< 1 Day','Response'],['100%','Satisfaction']].map(([n,l])=>(
              <div key={l} style={{textAlign:'center'}}>
                <div style={{fontFamily:'var(--serif)',fontSize:'clamp(1.2rem,2vw,1.7rem)',fontWeight:900,color:'#fff',lineHeight:1}}>{n}</div>
                <div style={{fontSize:'.56rem',fontWeight:700,letterSpacing:'.14em',textTransform:'uppercase',color:'rgba(255,255,255,.25)',marginTop:4}}>{l}</div>
              </div>
            ))}
          </div>
        </div>
        <div style={{position:'absolute',bottom:40,left:'50%',transform:'translateX(-50%)',display:'flex',flexDirection:'column',alignItems:'center',gap:6,animation:'slideUp .6s .7s both'}}>
          <span style={{fontSize:'.56rem',fontWeight:700,letterSpacing:'.2em',textTransform:'uppercase',color:'rgba(255,255,255,.2)'}}>Scroll</span>
          <div style={{width:1,height:48,background:'linear-gradient(to bottom,rgba(255,255,255,.3),transparent)',animation:'scrollPulse 2s ease-in-out infinite'}}/>
        </div>
      </div>
      <div style={{position:'absolute',bottom:0,left:0,right:0,height:160,background:'linear-gradient(to bottom,transparent,#020810)',pointerEvents:'none'}}/>
    </section>
  );
}

function InfoCards() {
  const [ref, vis] = useInView(.1);
  const cards = [
    {Icon:Mail,    col:'#0057ff',rgb:'0,87,255',   label:'Email Us',      val:'synnoviqtechnologies@gmail.com',sub:'We reply within 1 business day',href:'mailto:synnoviqtechnologies@gmail.com'},
    {Icon:MapPin,  col:'#7c3aed',rgb:'124,58,237', label:'Find Us',       val:'Kovilpatti, Tamil Nadu',         sub:'India — 628 502',               href:'https://maps.app.goo.gl/iEabAHETadFuYYnk9'},
    {Icon:Clock,   col:'#db2777',rgb:'219,39,119', label:'Working Hours', val:'Mon – Sat',                      sub:'9 AM – 8 PM IST',               href:null},
    {Icon:Zap,     col:'#059669',rgb:'5,150,105',  label:'Response Time', val:'< 24 Hours',                     sub:'On business days',              href:null},
  ];
  return (
    <section ref={ref} style={{background:'#020810',padding:'80px 0 0'}}>
      <div style={{maxWidth:1200,margin:'0 auto',padding:'0 clamp(20px,5vw,80px)'}}>
        <div style={{display:'grid',gap:16}} className="info-grid">
          {cards.map(({Icon,col,rgb,label,val,sub,href},i)=>{
            const inner = (
              <div style={{padding:'28px 24px',borderRadius:18,background:`linear-gradient(135deg,rgba(${rgb},.08) 0%,rgba(${rgb},.03) 100%)`,border:`1px solid rgba(${rgb},.2)`,opacity:vis?1:0,transform:vis?'none':'translateY(32px)',transition:`opacity .7s ${i*.1}s ease,transform .7s ${i*.1}s cubic-bezier(.16,1,.3,1)`,cursor:href?'pointer':'default',position:'relative',overflow:'hidden'}}>
                <div style={{position:'absolute',top:0,left:0,right:0,height:2,background:`linear-gradient(to right,${col},transparent)`}}/>
                <div style={{width:48,height:48,borderRadius:14,background:`rgba(${rgb},.15)`,border:`1px solid rgba(${rgb},.3)`,display:'flex',alignItems:'center',justifyContent:'center',color:col,marginBottom:16}}><Icon size={20}/></div>
                <div style={{fontSize:'.58rem',fontWeight:700,letterSpacing:'.16em',textTransform:'uppercase',color:col,marginBottom:6}}>{label}</div>
                <div style={{fontFamily:'var(--serif)',fontSize:'clamp(.95rem,1.5vw,1.15rem)',fontWeight:800,color:'#fff',lineHeight:1.2,marginBottom:4}}>{val}</div>
                <div style={{fontSize:'.75rem',color:'rgba(255,255,255,.35)'}}>{sub}</div>
                {href&&<div style={{position:'absolute',bottom:20,right:20,opacity:.4}}><ArrowRight size={14} color="#fff"/></div>}
              </div>
            );
            return href
              ? <a key={label} href={href} target={href.startsWith('http')?'_blank':undefined} rel="noopener noreferrer" style={{textDecoration:'none'}}>{inner}</a>
              : <div key={label}>{inner}</div>;
          })}
        </div>
      </div>
    </section>
  );
}

function ContactForm() {
  const [ref, vis] = useInView(.08);
  const [form, setForm] = useState({name:'',email:'',phone:'',subject:'',message:'',privacy:false});
  const [status, setStatus] = useState('idle');
  const [errors, setErrors] = useState({});
  const [focused, setFocused] = useState(null);

  const change = e => {
    const {name,value,type,checked} = e.target;
    setForm(p=>({...p,[name]:type==='checkbox'?checked:value}));
    if (errors[name]) setErrors(p=>({...p,[name]:false}));
  };

  const validate = () => {
    const e = {};
    if (!form.name.trim()) e.name = true;
    if (!form.email.trim()||!/\S+@\S+\.\S+/.test(form.email)) e.email = true;
    if (!form.subject) e.subject = true;
    if (!form.message.trim()) e.message = true;
    if (!form.privacy) e.privacy = true;
    setErrors(e); return Object.keys(e).length===0;
  };

  const submit = async () => {
    if (!validate()) return;
    if (!CONFIGURED) {
      // Demo mode — show success without sending
      setStatus('loading');
      await new Promise(r=>setTimeout(r,1000));
      setStatus('success');
      return;
    }
    setStatus('loading');
    try {
      if (!window.emailjs) {
        await new Promise((res,rej)=>{
          const s = document.createElement('script');
          s.src = 'https://cdn.jsdelivr.net/npm/@emailjs/browser@4/dist/email.min.js';
          s.onload=res; s.onerror=rej;
          document.head.appendChild(s);
        });
        window.emailjs.init(EJS_KEY);
      }
      await window.emailjs.send(EJS_SERVICE, EJS_TEMPLATE, {
        from_name: form.name, from_email: form.email,
        phone: form.phone||'Not provided',
        subject: form.subject, message: form.message,
        to_email: TO_EMAIL,
      });
      setStatus('success');
      setForm({name:'',email:'',phone:'',subject:'',message:'',privacy:false});
    } catch { setStatus('error'); }
  };

  const IS = name => ({
    width:'100%', boxSizing:'border-box', padding:'14px 16px',
    background:focused===name?'rgba(255,255,255,.06)':'rgba(255,255,255,.03)',
    border:errors[name]?'1px solid rgba(239,68,68,.6)':focused===name?'1px solid rgba(0,87,255,.6)':'1px solid rgba(255,255,255,.1)',
    borderRadius:12, color:'#fff', fontSize:'.93rem',
    fontFamily:'var(--sans)', outline:'none', transition:'all .2s ease',
    boxShadow:focused===name?'0 0 0 3px rgba(0,87,255,.12)':'none',
  });
  const LS = {display:'block',fontSize:'.62rem',fontWeight:700,letterSpacing:'.14em',textTransform:'uppercase',color:'rgba(255,255,255,.4)',marginBottom:8};

  return (
    <section style={{background:'#020810',padding:'80px 0 120px'}}>
      <div style={{maxWidth:1200,margin:'0 auto',padding:'0 clamp(20px,5vw,80px)'}}>
        <div ref={ref} style={{display:'grid',gap:48,alignItems:'start'}} className="contact-grid">

          {/* LEFT — map */}
          <div style={{opacity:vis?1:0,transform:vis?'none':'translateX(-40px)',transition:'opacity .8s ease,transform .8s cubic-bezier(.16,1,.3,1)'}}>
            <div style={{marginBottom:32}}>
              <div style={{display:'flex',alignItems:'center',gap:10,marginBottom:16}}>
                <div style={{width:24,height:2,background:'#0057ff',borderRadius:1}}/>
                <span style={{fontSize:'.62rem',fontWeight:700,letterSpacing:'.2em',textTransform:'uppercase',color:'rgba(255,255,255,.35)'}}>Find Us</span>
              </div>
              <h2 style={{fontFamily:'var(--serif)',fontSize:'clamp(2rem,4vw,3rem)',fontWeight:900,color:'#fff',letterSpacing:'-.04em',lineHeight:1.05,marginBottom:12}}>
                We're Based in<br/><span style={{color:'#5aa8ff',fontStyle:'italic'}}>Tamil Nadu.</span>
              </h2>
              <p style={{fontSize:'.9rem',color:'rgba(255,255,255,.38)',lineHeight:1.85}}>Kovilpatti, Tamil Nadu — working with clients globally. Remote-ready, always reachable.</p>
            </div>

            <div style={{borderRadius:20,overflow:'hidden',border:'1px solid rgba(255,255,255,.1)',marginBottom:28,position:'relative'}}>
              <div style={{position:'absolute',inset:0,background:'rgba(0,23,80,.25)',pointerEvents:'none',zIndex:1,mixBlendMode:'multiply'}}/>
              <div style={{position:'absolute',inset:0,border:'1px solid rgba(0,87,255,.2)',borderRadius:20,zIndex:2,pointerEvents:'none'}}/>
              <iframe
                title="Synnoviq Location"
                src={MAP_SRC}
                width="100%" height="320"
                style={{display:'block',border:0,filter:'invert(90%) hue-rotate(180deg) saturate(.55) brightness(.85)'}}
                allowFullScreen loading="lazy"
                referrerPolicy="no-referrer-when-downgrade"
              />
              <a href="https://maps.app.goo.gl/iEabAHETadFuYYnk9" target="_blank" rel="noopener noreferrer"
                style={{position:'absolute',bottom:16,left:16,zIndex:3,display:'flex',alignItems:'center',gap:8,padding:'8px 14px',borderRadius:999,background:'rgba(0,0,0,.7)',backdropFilter:'blur(12px)',border:'1px solid rgba(0,87,255,.4)',color:'#fff',textDecoration:'none',fontSize:'.7rem',fontWeight:700}}>
                <MapPin size={12} color="#5aa8ff"/> Open in Maps <ArrowRight size={10}/>
              </a>
            </div>

            <a href="mailto:synnoviqtechnologies@gmail.com"
              style={{display:'flex',alignItems:'center',gap:14,padding:'18px 22px',borderRadius:16,border:'1px solid rgba(0,87,255,.25)',background:'rgba(0,87,255,.07)',textDecoration:'none',transition:'all .25s ease'}}
              onMouseEnter={e=>{e.currentTarget.style.borderColor='rgba(0,87,255,.5)';e.currentTarget.style.background='rgba(0,87,255,.12)';}}
              onMouseLeave={e=>{e.currentTarget.style.borderColor='rgba(0,87,255,.25)';e.currentTarget.style.background='rgba(0,87,255,.07)';}}>
              <div style={{width:44,height:44,borderRadius:12,background:'rgba(0,87,255,.2)',border:'1px solid rgba(0,87,255,.4)',display:'flex',alignItems:'center',justifyContent:'center',color:'#5aa8ff',flexShrink:0}}><Mail size={18}/></div>
              <div style={{flex:1,minWidth:0}}>
                <div style={{fontSize:'.6rem',fontWeight:700,letterSpacing:'.14em',textTransform:'uppercase',color:'rgba(0,87,255,.8)',marginBottom:3}}>Or email directly</div>
                <div style={{fontSize:'.82rem',fontWeight:600,color:'#fff',overflow:'hidden',textOverflow:'ellipsis',whiteSpace:'nowrap'}}>synnoviqtechnologies@gmail.com</div>
              </div>
              <ArrowRight size={16} color="rgba(255,255,255,.3)"/>
            </a>
          </div>

          {/* RIGHT — form */}
          <div style={{opacity:vis?1:0,transform:vis?'none':'translateX(40px)',transition:'opacity .8s .15s ease,transform .8s .15s cubic-bezier(.16,1,.3,1)'}}>
            {status==='success' ? (
              <div style={{padding:'60px 40px',borderRadius:24,background:'rgba(5,150,105,.08)',border:'1px solid rgba(5,150,105,.25)',textAlign:'center'}}>
                <div style={{width:72,height:72,borderRadius:'50%',background:'rgba(5,150,105,.15)',border:'1px solid rgba(5,150,105,.4)',display:'flex',alignItems:'center',justifyContent:'center',margin:'0 auto 24px',color:'#34d399'}}><CheckCircle size={32}/></div>
                <h3 style={{fontFamily:'var(--serif)',fontSize:'2rem',fontWeight:900,color:'#fff',marginBottom:10,letterSpacing:'-.03em'}}>Message Sent!</h3>
                <p style={{color:'rgba(255,255,255,.45)',lineHeight:1.8,marginBottom:32,fontSize:'.9rem'}}>We'll reply within 1 business day.</p>
                <button onClick={()=>setStatus('idle')} style={{padding:'12px 28px',borderRadius:12,background:'rgba(255,255,255,.08)',border:'1px solid rgba(255,255,255,.15)',color:'#fff',fontSize:'.84rem',fontWeight:700,cursor:'pointer',fontFamily:'var(--sans)'}}>Send Another</button>
              </div>
            ) : (
              <div style={{borderRadius:24,background:'rgba(255,255,255,.03)',border:'1px solid rgba(255,255,255,.08)',padding:'clamp(24px,4vw,40px)',position:'relative',overflow:'hidden'}}>
                <div style={{position:'absolute',top:0,left:0,right:0,height:2,background:'linear-gradient(90deg,#0057ff,#7c3aed,#db2777)'}}/>
                <div style={{marginBottom:28}}>
                  <div style={{display:'flex',alignItems:'center',gap:10,marginBottom:12}}>
                    <div style={{width:36,height:36,borderRadius:10,background:'rgba(0,87,255,.15)',border:'1px solid rgba(0,87,255,.3)',display:'flex',alignItems:'center',justifyContent:'center',color:'#5aa8ff'}}><MessageSquare size={16}/></div>
                    <span style={{fontFamily:'var(--serif)',fontSize:'1.3rem',fontWeight:800,color:'#fff'}}>Send a Message</span>
                  </div>
                  <p style={{fontSize:'.78rem',color:'rgba(255,255,255,.3)',lineHeight:1.7}}>Fill in the form and we'll get back to you ASAP.</p>
                </div>

                {!CONFIGURED&&(
                  <div style={{marginBottom:20,padding:'12px 14px',borderRadius:10,background:'rgba(245,158,11,.08)',border:'1px solid rgba(245,158,11,.28)',fontSize:'.75rem',color:'rgba(255,200,50,.85)',lineHeight:1.6}}>
                    ⚠️ EmailJS not configured — set your credentials in Contact.jsx. Form shows demo success for now.
                  </div>
                )}

                <div style={{display:'flex',flexDirection:'column',gap:18}}>
                  <div style={{display:'grid',gap:14}} className="form-row-2">
                    <div>
                      <label style={LS}>Full Name <span style={{color:'#ef4444'}}>*</span></label>
                      <input name="name" value={form.name} onChange={change} placeholder="Your name" style={IS('name')} onFocus={()=>setFocused('name')} onBlur={()=>setFocused(null)}/>
                      {errors.name&&<div style={{fontSize:'.66rem',color:'#ef4444',marginTop:5}}>Name is required</div>}
                    </div>
                    <div>
                      <label style={LS}>Email <span style={{color:'#ef4444'}}>*</span></label>
                      <input name="email" type="email" value={form.email} onChange={change} placeholder="you@example.com" style={IS('email')} onFocus={()=>setFocused('email')} onBlur={()=>setFocused(null)}/>
                      {errors.email&&<div style={{fontSize:'.66rem',color:'#ef4444',marginTop:5}}>Valid email required</div>}
                    </div>
                  </div>
                  <div style={{display:'grid',gap:14}} className="form-row-2">
                    <div>
                      <label style={LS}>Phone <span style={{fontSize:'.6rem',fontWeight:400,color:'rgba(255,255,255,.2)'}}>(optional)</span></label>
                      <input name="phone" value={form.phone} onChange={change} placeholder="+91 00000 00000" style={IS('phone')} onFocus={()=>setFocused('phone')} onBlur={()=>setFocused(null)}/>
                    </div>
                    <div>
                      <label style={LS}>Subject <span style={{color:'#ef4444'}}>*</span></label>
                      <select name="subject" value={form.subject} onChange={change} style={{...IS('subject'),cursor:'pointer',color:form.subject?'#fff':'rgba(255,255,255,.3)'}} onFocus={()=>setFocused('subject')} onBlur={()=>setFocused(null)}>
                        <option value="" style={{background:'#0d1b3e',color:'rgba(255,255,255,.5)'}}>Select topic…</option>
                        {['Project Request','Full Stack Development','Game Development','UI/UX Design','Partnership','Internship','General Inquiry','Other'].map(o=>(
                          <option key={o} value={o} style={{background:'#0d1b3e'}}>{o}</option>
                        ))}
                      </select>
                      {errors.subject&&<div style={{fontSize:'.66rem',color:'#ef4444',marginTop:5}}>Please select a topic</div>}
                    </div>
                  </div>
                  <div>
                    <label style={LS}>Message <span style={{color:'#ef4444'}}>*</span></label>
                    <textarea name="message" value={form.message} onChange={change} placeholder="Tell us about your project — scope, timeline, goals…" style={{...IS('message'),minHeight:130,resize:'vertical',lineHeight:1.65}} onFocus={()=>setFocused('message')} onBlur={()=>setFocused(null)}/>
                    {errors.message&&<div style={{fontSize:'.66rem',color:'#ef4444',marginTop:5}}>Message is required</div>}
                    <div style={{textAlign:'right',fontSize:'.62rem',color:'rgba(255,255,255,.2)',marginTop:4}}>{form.message.length} chars</div>
                  </div>
                  <div>
                    <div style={{display:'flex',alignItems:'flex-start',gap:10}}>
                      <input type="checkbox" id="priv" name="privacy" checked={form.privacy} onChange={change} style={{width:16,height:16,marginTop:2,accentColor:'#0057ff',cursor:'pointer',flexShrink:0}}/>
                      <label htmlFor="priv" style={{fontSize:'.8rem',color:'rgba(255,255,255,.38)',cursor:'pointer',lineHeight:1.6}}>
                        I agree to the <a href="/privacy-policy" style={{color:'#5aa8ff',textDecoration:'none'}}>Privacy Policy</a> and consent to being contacted. <span style={{color:'#ef4444'}}>*</span>
                      </label>
                    </div>
                    {errors.privacy&&<div style={{fontSize:'.66rem',color:'#ef4444',marginTop:5,paddingLeft:26}}>Please accept to continue</div>}
                  </div>
                  {status==='error'&&(
                    <div style={{display:'flex',alignItems:'center',gap:9,padding:'12px 14px',borderRadius:10,background:'rgba(239,68,68,.08)',border:'1px solid rgba(239,68,68,.28)',color:'#fca5a5',fontSize:'.8rem'}}>
                      <AlertCircle size={14}/> Something went wrong. Please email us directly.
                    </div>
                  )}
                  <button onClick={submit} disabled={status==='loading'} style={{display:'flex',alignItems:'center',justifyContent:'center',gap:9,padding:'15px 28px',borderRadius:14,border:'none',background:status==='loading'?'rgba(0,87,255,.5)':'linear-gradient(135deg,#0057ff,#2563eb)',color:'#fff',fontSize:'.9rem',fontWeight:700,cursor:status==='loading'?'not-allowed':'pointer',fontFamily:'var(--sans)',boxShadow:'0 8px 24px rgba(0,87,255,.4)',transition:'all .25s ease',position:'relative',overflow:'hidden'}}
                    onMouseEnter={e=>{if(status!=='loading'){e.currentTarget.style.transform='translateY(-2px)';e.currentTarget.style.boxShadow='0 14px 32px rgba(0,87,255,.55)';}}}
                    onMouseLeave={e=>{e.currentTarget.style.transform='';e.currentTarget.style.boxShadow='0 8px 24px rgba(0,87,255,.4)';}}>
                    {status==='loading'
                      ? <><span style={{width:16,height:16,border:'2px solid rgba(255,255,255,.3)',borderTopColor:'#fff',borderRadius:'50%',display:'inline-block',animation:'spin .8s linear infinite'}}/> Sending…</>
                      : <><Send size={15}/> Send Message <ArrowRight size={14}/></>}
                  </button>
                  <p style={{fontSize:'.65rem',color:'rgba(255,255,255,.2)',textAlign:'center',lineHeight:1.6}}>🔒 Your info is encrypted and never shared with third parties.</p>
                </div>
              </div>
            )}
          </div>
        </div>
      </div>
    </section>
  );
}

